/**
 * A Transition corresponds to a line between shapes on a .flow page (that is, an edge in the Flow's state machine).
 * When the value field (displayed as a label on the transition on the diagram) matches the stringified
 * result of the transition's 'from' activity, Flow execution proceeds to the 'to' activity.
 * @class Transition
 * @memberof module:jibo-flow-core
 * @param {string} frm The uuid of the activity this transition comes from.
 * @param {string} to The uuid of the activity this transition goes to.
 * @param {string} value The value (i.e. label) that must be matched for the transition to be used.
 * @internal
 */
class Transition {
    public frm:string;
    public to:string;
    public value:string;

    constructor(frm:string, to:string, value:string) {
        this.frm = frm;
        this.to = to;
        this.value = value;
    }
}

export default Transition;