import Procedure from './Procedure';

/**
 * A FlowRoot is the top level container for a Flow-program.
 * Think of it as the read-only, in-memory, executable representation of a Flow.
 * It holds references to all the procedures that are accessed during execution.
 * @class FlowRoot
 * @memberof module:jibo-flow-core
 * @param {any} loader The loader appropriate to the type of loading being done.
 * This will either be an instance of the GojsLoader class (for design-time loading of .flow files from the
 * static-analysis tools), or the TreeLoader class (for runtime loading of the Javascript
 * functions produced during the build step from .flow files by Behaviorify).
 * @internal
 */
class FlowRoot {
    public procedures:{ [key:string]:Procedure };
    public global_inits:{ [key:string]:string };
    public loader:any;
    public startProcedureOrName:string;
    public startUri:string;

    constructor(loader:any) {
        this.procedures = {};
        this.global_inits = {};
        this.loader = loader;
    }

    /**
     * Prepare the FlowRoot for execution (saving away the startUri and startProcedure).
     * @param {string} uri the .flow file where execution is to begin.
     */
    setStartInfoFromUri(uri:any) {
        this.startUri = this.loader.getUri(uri);
        this.startProcedureOrName = this.loader.getStartProcedureOrName(uri);
    }

    /**
     * Load a procedure relative to the current Uri. 
     * @param {string} currentUri the current uri
     * @param {string} procedureObjectOrName the procedure object or procedure name to be loaded
     * @returns {jibo.flow.Procedure}
     */
    loadProcedure(currentUri:string, procedureObjectOrName:string) {
        return this.loader.loadProcedureRelative(currentUri, procedureObjectOrName);
    }

    /**
     * Not used by runtime -- called from Flow editor (and only for .flow file types) to find
     * the Flow.Start activity on a page.
     * @returns {jibo.flow.Activity}
     */
    public getStartActivity() {
        return this.getStartProcedure().getBeginActivity();
    }

    /**
     * Get the start procedure for this FlowRoot (determined during setStartInfoFromUri).
     * @returns {jibo.flow.Procedure}
     */
    public getStartProcedure() {
        return this.loader.loadProcedure(this.startUri);
    }

    public getStartProcedureOrName() {
        return this.startProcedureOrName;
    }

}

export default FlowRoot;
